import re, pickle

# ============================================================
# 1. 加载 cnradical 字典
# ============================================================
dpath = r'C:\Users\Administrator\AppData\Local\Programs\Python\Python312\Lib\site-packages\cnradical\data\dictionary.pickle'
with open(dpath, 'rb') as f:
    cn_dict = pickle.load(f)
PINYIN_DICT = cn_dict['pinyin']
RADICAL_DICT = cn_dict['radical']

# ============================================================
# 2. 读取现有高质量CHAR_DB_RAW
# ============================================================
def parse_existing():
    text = open(r'C:\Users\Administrator\WorkBuddy\2026-06-02-task-5\识字训练应用.html', 'r', encoding='utf-8').read()
    match = re.search(r'const CHAR_DB_RAW = \[(.*?)\];', text, re.DOTALL)
    if not match:
        return {}, []
    raw = match.group(1)
    existing = {}
    order = []
    # Parse each entry: ["字","拼音","释义","年级","阅读","部首",笔数,"笔画顺序"]
    entry_pattern = re.compile(r'\["([^"]*)","([^"]*)","([^"]*)","([\d]+)","([^"]*)","([^"]*)",(\d+),"([^"]*)"\]')
    for m in entry_pattern.finditer(raw):
        char = m.group(1)
        entry = [m.group(1), m.group(2), m.group(3), m.group(4), m.group(5),
                 m.group(6), int(m.group(7)), m.group(8)]
        if char not in existing:
            existing[char] = entry
            order.append(char)
    print(f"Loaded {len(existing)} existing quality entries")
    return existing, order

existing_entries, existing_order = parse_existing()

