# 5. 阅读故事生成
# ============================================================
def generate_reading(char, grade):
    templates = [
        f"小明学会了写「{char}」字，在纸上写了一遍又一遍。老师夸他写得真工整，他心里美滋滋的。",
        f"「{char}」这个字很有趣。每天早晨，小明都会朗读课文，遇到这个字就仔细品味它的含义。",
        f"语文课上，老师教大家认识「{char}」字。小明举手说出它组成的词语，同学们都为他鼓掌。",
        f"妈妈教小明认字，第一个就是「{char}」。小明用这个字组了好多词，妈妈欣慰地笑了。",
        f"小明在课外书里遇到了「{char}」字，赶紧拿字典查读音和意思，又学到了一个新知识。",
        f"汉字博大精深，「{char}」字含义丰富。小明把它写在田字格里，一笔一画都很认真。",
        f"爸爸给小明讲故事，故事里出现了「{char}」字。小明记住了这个字，还学会了用它造句。",
        f"小明用「{char}」字写了一句话：细心观察就能发现生活中的美好。老师看了连连称赞。",
    ]
    return templates[hash(char) % len(templates)]

def generate_meaning(char, grade):
    generic = {
        1: "一年级常用字", 2: "二年级基础字", 3: "三年级核心字",
        4: "四年级必会字", 5: "五年级拓展字", 6: "六年级综合字",
    }
    return generic.get(grade, "常用汉字")

def get_pinyin(char):
    py = PINYIN_DICT.get(char, '')
    if py and py != 'None':
        return py
    try:
        from pypinyin import pinyin, Style
        r = pinyin(char, style=Style.TONE)
        if r and r[0]: return r[0][0]
    except:
        pass
    return ''

def get_radical(char):
    rad = RADICAL_DICT.get(char, '')
    if rad and rad != 'None':
        return rad
    return '?'

def get_stroke_count(char):
    return FULL_STROKES.get(char, 0)

def build_chardb():
    # 收集所有PEP字符
    all_pep = set()
    for grade in range(1, 7):
        grade_data = GRADE_CHARS.get(grade, {})
        for chars_str in grade_data.values():
            for ch in chars_str:
                if ch.strip():
                    all_pep.add(ch)
    
    # 合并策略：优先使用现有高质量数据
    result = {}
    result_order = []
    
    # 先处理有现有数据的字符
    for pep_char in all_pep:
        if pep_char in existing_entries:
            # 使用现有高质量数据
            entry = existing_entries[pep_char]
            result[pep_char] = entry
            result_order.append(pep_char)
    
    # 再处理没有现有数据的字符
    for grade in range(1, 7):
        grade_data = GRADE_CHARS.get(grade, {})
        for chars_str in grade_data.values():
            for ch in chars_str:
                if not ch.strip() or ch in result:
                    continue
                py = get_pinyin(ch)
                meaning = generate_meaning(ch, grade)
                reading = generate_reading(ch, grade)
                rad = get_radical(ch)
                sc = get_stroke_count(ch)
                entry = [ch, py, meaning, str(grade), reading, rad, sc, '']
                result[ch] = entry
                result_order.append(ch)
    
    # 按年级排序输出
    by_grade = {g: [] for g in range(1, 7)}
    for ch in result_order:
        entry = result[ch]
        grade = int(entry[3])
        if 1 <= grade <= 6:
            by_grade[grade].append(entry)
    
    output = []
    for grade in range(1, 7):
        entries = by_grade[grade]
        for entry in entries:
            output.append(entry)
    
    return output

def format_entry(entry):
    char, py, meaning, grade, reading, radical, sc, so = entry
    reading = reading.replace('\\', '\\\\').replace("'", "\\'")
    meaning = meaning.replace('\\', '\\\\').replace("'", "\\'")
    return f'["{char}","{py}","{meaning}","{grade}","{reading}","{radical}",{sc},"{so}"]'

if __name__ == '__main__':
    chars = build_chardb()
    zero_count = sum(1 for e in chars if e[6] == 0)
    print(f"// 小学1-6年级国标生字完整数据库")
    print(f"// 自动生成于 2026-06-02")
    print(f"// 总数: {len(chars)} 字 (零笔画: {zero_count})")
    print(f"// 格式：[汉字, 拼音, 释义, 年级, 专属小阅读, 偏旁部首, 笔画数, 笔画顺序]")
    print(f"// 数据来源：人教版教材 + cnradical + 标准笔画库 + 人工校对")
    print(f"const CHAR_DB_RAW = [")
    
    current_grade = 0
    for i, entry in enumerate(chars):
        grade = int(entry[3])
        if grade != current_grade:
            current_grade = grade
            gname = ['','一','二','三','四','五','六'][grade]
            print(f'// {"=" * 60}')
            print(f'// {gname}年级')
            print(f'// {"=" * 60}')
        comma = ',' if i < len(chars) - 1 else ''
        print(f'{format_entry(entry)}{comma}')
    
    print(f'];')
    
    gc = {}
    for e in chars:
        g = int(e[3]); gc[g] = gc.get(g, 0) + 1
    stats = ','.join([f'{g}年级{gc.get(g,0)}字' for g in range(1,7)])
    print(f'\n// 统计：{stats} 共{len(chars)}字')
